const tooltip = document.getElementById('tooltip');
const tooltipTitle = document.getElementById('tooltip-title');
const tooltipBody = document.getElementById('tooltip-body');
const activePartId = document.getElementById('active-part-id');
const diagnosticConsole = document.getElementById('diagnostic-console');

// Animation State & Blending
let activeState = 'idle'; // 'run', 'somersault', 'idle', 'pose'
let somersaultProgress = { value: 0 }; // Animate this via GSAP for flip transition
let isIntroComplete = false;

// GLTF Loader State
let mixer = null;
let loadedAnimations = [];
