    const armCuffLGeo = new THREE.CylinderGeometry(0.14, 0.18, 0.35, 16);
    const armCuffL = new THREE.Mesh(armCuffLGeo, orangeMaterial);
    armCuffL.position.y = -0.22;
    upperArmL.add(armCuffL);
    tagMesh(armCuffL, 'leftArm', 'Arm Plating', 'Thermal shielding casing');

    // Left Elbow Joint (Silver Sphere)
    const elL = new THREE.Group();
    elL.position.set(0, -0.48, 0);
    upperArmL.add(elL);
    joints.leftElbow = elL;

    const elSphereL = new THREE.Mesh(new THREE.SphereGeometry(0.15, 16, 16), silverMaterial);
