function setupDynamicFace() {
    faceCanvas = document.createElement('canvas');
    faceCanvas.width = 256;
    faceCanvas.height = 256;
    faceCtx = faceCanvas.getContext('2d');

    faceTexture = new THREE.CanvasTexture(faceCanvas);
    faceMaterial.map = faceTexture;
    faceMaterial.emissiveMap = faceTexture;
    faceMaterial.emissive = new THREE.Color(0x00f0ff);
    faceMaterial.emissiveIntensity = 1.3;

    drawFace(false);
}

function drawFace(blink = false) {
    // Clear screen
    faceCtx.fillStyle = '#07070a';
    faceCtx.fillRect(0, 0, 256, 256);

    faceCtx.strokeStyle = '#00f0ff';
    faceCtx.lineWidth = 14;
    faceCtx.lineCap = 'round';

    const eyeY = 115;
    const eyeR = 18;
    const leftEyeX = 85;
    const rightEyeX = 171;

    if (blink) {
        // Draw straight lines for blinking eyes
        faceCtx.beginPath();
        faceCtx.moveTo(leftEyeX - 18, eyeY);
        faceCtx.lineTo(leftEyeX + 18, eyeY);
        faceCtx.moveTo(rightEyeX - 18, eyeY);
        faceCtx.lineTo(rightEyeX + 18, eyeY);
        faceCtx.stroke();
    } else {
        // Draw smiling arches matching the reference image eyes
        faceCtx.beginPath();
        // Left Eye Arch
        faceCtx.arc(leftEyeX, eyeY + 6, eyeR, Math.PI, 0, true);
        // Right Eye Arch
        faceCtx.moveTo(rightEyeX + eyeR, eyeY + 6);
        faceCtx.arc(rightEyeX, eyeY + 6, eyeR, Math.PI, 0, true);
        faceCtx.stroke();
    }

    // Smiling V-mouth matching the updated image
    faceCtx.strokeStyle = '#00f0ff';
    faceCtx.lineWidth = 12;
    faceCtx.lineJoin = 'round';
    faceCtx.beginPath();
    faceCtx.moveTo(128 - 14, 155);
    faceCtx.lineTo(128, 168);
    faceCtx.lineTo(128 + 14, 155);
    faceCtx.stroke();

    // Trigger texture update in GPU
    faceTexture.needsUpdate = true;
}

function updateFaceBlink(time) {
    if (isGLTFLoaded) return; // Skip if external glb handles its own expression
    
    if (isBlinking) {
        if (time - lastBlinkTime > 0.15) { // Blink lasts 150ms
            isBlinking = false;
            drawFace(false);
        }
    } else {
        // Blink every 3.5 to 7 seconds
        if (time - lastBlinkTime > 3.5 + Math.random() * 3.5) {
            isBlinking = true;
            lastBlinkTime = time;
            drawFace(true);
        }
    }
}

// -------------------------------------------------------------
// EXTERNAL GLTF MODEL LOADER (robot.glb)
// -------------------------------------------------------------
function loadGLTFModel() {
    const loader = new THREE.GLTFLoader();
    
    loader.load('robot.glb', (gltf) => {
        console.log('Successfully loaded "robot.glb". Replacing procedural model.');
        
        // Remove procedural fallback
        robotGroup.remove(proceduralRobot);
        
        const loadedModel = gltf.scene;
        
        // Apply appropriate scale and position offsets to match scene
        // Adjust these to match your model's native size
        loadedModel.scale.set(1.0, 1.0, 1.0); 
        loadedModel.position.set(0, 0, 0);
        
        robotGroup.add(loadedModel);
        isGLTFLoaded = true;

        // Auto-tag meshes in loaded GLTF for Raycaster based on names
        loadedModel.traverse((node) => {
            if (node.isMesh) {
                node.castShadow = true;
                node.receiveShadow = true;
                
                // Set default emissive settings to prevent null checks
                if (!node.material.emissive) {
                    node.material = node.material.clone();
                    node.material.emissive = new THREE.Color(0x000000);
                    node.material.emissiveIntensity = 0;
                }

                const name = node.name.toLowerCase();
                if (name.includes('head') || name.includes('face') || name.includes('eye') || name.includes('antenna')) {
                    node.userData = {
                        part: 'head',
                        fullName: 'Cognitive Cortex Shell',
                        specs: 'Synapse V4.2 | 98.4% Sync | Temp: 36.8°C'
                    };
                } else if (name.includes('torso') || name.includes('chest') || name.includes('body') || name.includes('spine') || name.includes('neck')) {
                    node.userData = {
                        part: 'torso',
                        fullName: 'Quantum Fusion Core Container',
                        specs: 'Quantum Core Cell | Energy: 87.2% | Stability: 100%'
                    };
                } else if (name.includes('left') && (name.includes('arm') || name.includes('hand') || name.includes('finger') || name.includes('shoulder'))) {
                    node.userData = {
                        part: 'leftArm',
                        fullName: 'Actuator Arm Assembly (L)',
                        specs: 'Harmonic Drive Gear | Max Torque: 450 Nm | Load: 12%'
                    };
                } else if (name.includes('right') && (name.includes('arm') || name.includes('hand') || name.includes('finger') || name.includes('shoulder'))) {
                    node.userData = {
                        part: 'rightArm',
                        fullName: 'Actuator Arm Assembly (R)',
                        specs: 'Harmonic Drive Gear | Max Torque: 450 Nm | Load: 8%'
                    };
                } else {
                    // Default to legs for other meshes
                    node.userData = {
                        part: 'legs',
                        fullName: 'Kinetic Thruster Pod Stabilizers',
                        specs: 'Magnetic Dampers: Active | Gravity Calibration: Stable | Charge: 100%'
                    };
                }
            }
        });

        // Setup Animation Mixer
        mixer = new THREE.AnimationMixer(loadedModel);
        loadedAnimations = gltf.animations;
        
        // Start playing Idle animation
        playGLTFAnimation('Idle');
    }, 
    // Progress
    undefined, 
    // Error loading model
    (err) => {
        console.warn('Could not load external "robot.glb". Running fully rigged procedural robot model.');
    });
}

function playGLTFAnimation(name) {
    if (!mixer || !loadedAnimations.length) return;
    
    // Find animation clip by name (Run, Somersault, Idle, Pose)
    const clip = THREE.AnimationClip.findByName(loadedAnimations, name);
    if (clip) {
        const action = mixer.clipAction(clip);
        action.reset().fadeIn(0.3).play();
        
        // Smoothly fade out other animations
        mixer._actions.forEach((act) => {
            if (act !== action) {
                act.fadeOut(0.3);
            }
        });
    } else {
        console.warn(`Animation clip "${name}" not found in GLTF file.`);
    }
}

// -------------------------------------------------------------
// PROCEDURAL ANIMATION ENGINE (LERP Blending & Waves)
// -------------------------------------------------------------
function updateProceduralAnimations(time) {
    if (isGLTFLoaded) return; // Skip if external glb handles animation

    // Dictionary of target rotations for LERP blending
    const targets = {
        rootPos: { x: 0, y: 0, z: 0 },
        rootRot: { x: 0, y: 0, z: 0 },
        torsoRot: { x: 0, y: 0, z: 0 },
        neckRot: { x: 0, y: 0, z: 0 },
        headRot: { x: 0, y: 0, z: 0 },
        
        shL: { x: 0, y: 0, z: 0.1 },
        shR: { x: 0, y: 0, z: -0.1 },
        elL: { x: -0.2, y: 0, z: 0 },
        elR: { x: -0.2, y: 0, z: 0 },
        
        hipL: { x: 0, y: 0, z: 0 },
        hipR: { x: 0, y: 0, z: 0 },
        kneeL: { x: 0, y: 0, z: 0 },
        kneeR: { x: 0, y: 0, z: 0 },
        footL: { x: 0, y: 0, z: 0 },
        footR: { x: 0, y: 0, z: 0 }
    };

    // Calculate angles based on active state
    if (activeState === 'run') {
        const speed = 11.0;
        const cycle = time * speed;
        
        // Hip movement (alternating back and forth)
        targets.hipL.x = Math.sin(cycle) * 0.7;
        targets.hipR.x = -Math.sin(cycle) * 0.7;
        
        // Knee bends out of phase
        targets.kneeL.x = (Math.cos(cycle) + 1.0) * 0.45;
        targets.kneeR.x = (-Math.cos(cycle) + 1.0) * 0.45;
        
        // Ankles flex
        targets.footL.x = Math.sin(cycle + 0.5) * 0.2;
        targets.footR.x = -Math.sin(cycle + 0.5) * 0.2;

        // Shoulder arms swing out of phase with legs
        targets.shL.x = -Math.sin(cycle) * 0.8;
        targets.shR.x = Math.sin(cycle) * 0.8;
        targets.shL.z = 0.25 + Math.sin(cycle * 0.5) * 0.1;
        targets.shR.z = -0.25 - Math.sin(cycle * 0.5) * 0.1;
        
        // Elbow bend
        targets.elL.x = -0.6 + Math.sin(cycle) * 0.3;
        targets.elR.x = -0.6 - Math.sin(cycle) * 0.3;

        // Torso bobs and rotates slightly
        targets.torsoRot.y = Math.sin(cycle) * 0.12;
        targets.torsoRot.x = 0.15; // Lean forward
        targets.rootPos.y = Math.abs(Math.sin(cycle * 2.0)) * 0.28; // Vertical bobbing
        
        // Head stabilization
        targets.headRot.x = -0.1;
        targets.headRot.y = -Math.sin(cycle) * 0.08;
        
    } else if (activeState === 'somersault') {
        const progress = somersaultProgress.value;
        const angle = progress * Math.PI * 2;
        
        // Jump height arc
        targets.rootPos.y = Math.sin(progress * Math.PI) * 3.4;
        // Rotation flip on X-axis
        targets.rootRot.x = -angle;

        // Tuck limbs in tightly during somersault
        targets.hipL.x = -1.1;
        targets.hipR.x = -1.1;
        targets.kneeL.x = 1.4;
        targets.kneeR.x = 1.4;
        
        targets.shL.x = -1.2;
        targets.shR.x = -1.2;
        targets.shL.z = 0.3;
        targets.shR.z = -0.3;
        targets.elL.x = -1.5;
        targets.elR.x = -1.5;
        
        targets.torsoRot.x = 0.2;
        targets.headRot.x = 0.3;
        
    } else if (activeState === 'idle') {
        const breathing = Math.sin(time * 1.6);
        
        // Soft breathing motion
        targets.rootPos.y = breathing * 0.04;
        targets.torsoRot.x = breathing * 0.02 + 0.04; // Gentle lean
        targets.neckRot.x = -breathing * 0.015;
        targets.headRot.x = Math.sin(time * 0.8) * 0.03;
        targets.headRot.y = Math.cos(time * 0.5) * 0.05; // Looking around subtle

        // Arms hanging at side, swaying gently
        targets.shL.x = Math.sin(time * 1.6) * 0.06;
        targets.shL.z = 0.15 + Math.cos(time * 1.6) * 0.02;
        targets.shR.x = -Math.sin(time * 1.6) * 0.06;
        targets.shR.z = -0.15 - Math.cos(time * 1.6) * 0.02;
        
        targets.elL.x = -0.2 + Math.sin(time * 1.6) * 0.04;
        targets.elR.x = -0.2 - Math.sin(time * 1.6) * 0.04;
        
        // Hips slightly angled out for solid posture
        targets.hipL.z = -0.05;
        targets.hipR.z = 0.05;
        targets.hipL.x = 0.05;
        targets.hipR.x = 0.05;
        
    } else if (activeState === 'pose') {
        // Hero stance: One hand on hip, other greeting/pointing
        targets.rootPos.y = 0;
        targets.rootRot.x = 0;
        targets.rootRot.y = 0;
        targets.rootRot.z = 0;
        
        // Feet planted wide
        targets.hipL.z = -0.15;
        targets.hipR.z = 0.15;
        targets.hipL.x = -0.1;
        targets.hipR.x = 0.2;
        targets.kneeL.x = 0.25;
        targets.kneeR.x = 0.1;

        // Left arm hand on hip
        targets.shL.x = 0.3;
        targets.shL.y = -0.2;
        targets.shL.z = 0.4;
        targets.elL.x = -1.2;
        
        // Right arm raised, saluting/waving heroic pose
        targets.shR.x = -1.4;
        targets.shR.y = 0.3;
        targets.shR.z = -0.4;
        targets.elR.x = -0.4;
        
        targets.torsoRot.x = -0.05;
        targets.torsoRot.y = -0.15;
        targets.headRot.x = 0.05;
        targets.headRot.y = 0.2; // Looking confidently
    }

    // Apply LERP transition for smooth, snap-free animations
    const lerpSpeed = 0.12;
    
    // Apply position LERP
    joints.rootNode.position.x += (targets.rootPos.x - joints.rootNode.position.x) * lerpSpeed;
    joints.rootNode.position.y += (targets.rootPos.y - joints.rootNode.position.y) * lerpSpeed;
    joints.rootNode.position.z += (targets.rootPos.z - joints.rootNode.position.z) * lerpSpeed;

    // Apply rotations LERP
    joints.rootNode.rotation.x += (targets.rootRot.x - joints.rootNode.rotation.x) * lerpSpeed;
    joints.rootNode.rotation.y += (targets.rootRot.y - joints.rootNode.rotation.y) * lerpSpeed;
    joints.rootNode.rotation.z += (targets.rootRot.z - joints.rootNode.rotation.z) * lerpSpeed;

    joints.torso.rotation.x += (targets.torsoRot.x - joints.torso.rotation.x) * lerpSpeed;
    joints.torso.rotation.y += (targets.torsoRot.y - joints.torso.rotation.y) * lerpSpeed;
    joints.torso.rotation.z += (targets.torsoRot.z - joints.torso.rotation.z) * lerpSpeed;

    joints.neck.rotation.x += (targets.neckRot.x - joints.neck.rotation.x) * lerpSpeed;
    
    joints.head.rotation.x += (targets.headRot.x - joints.head.rotation.x) * lerpSpeed;
    joints.head.rotation.y += (targets.headRot.y - joints.head.rotation.y) * lerpSpeed;
    
    joints.leftShoulder.rotation.x += (targets.shL.x - joints.leftShoulder.rotation.x) * lerpSpeed;
    joints.leftShoulder.rotation.z += (targets.shL.z - joints.leftShoulder.rotation.z) * lerpSpeed;
    
    joints.rightShoulder.rotation.x += (targets.shR.x - joints.rightShoulder.rotation.x) * lerpSpeed;
    joints.rightShoulder.rotation.z += (targets.shR.z - joints.rightShoulder.rotation.z) * lerpSpeed;

    joints.leftElbow.rotation.x += (targets.elL.x - joints.leftElbow.rotation.x) * lerpSpeed;
    joints.rightElbow.rotation.x += (targets.elR.x - joints.rightElbow.rotation.x) * lerpSpeed;

    joints.leftHip.rotation.x += (targets.hipL.x - joints.leftHip.rotation.x) * lerpSpeed;
    joints.leftHip.rotation.z += (targets.hipL.z - joints.leftHip.rotation.z) * lerpSpeed;
    joints.rightHip.rotation.x += (targets.hipR.x - joints.rightHip.rotation.x) * lerpSpeed;
    joints.rightHip.rotation.z += (targets.hipR.z - joints.rightHip.rotation.z) * lerpSpeed;

    joints.leftKnee.rotation.x += (targets.kneeL.x - joints.leftKnee.rotation.x) * lerpSpeed;
    joints.rightKnee.rotation.x += (targets.kneeR.x - joints.rightKnee.rotation.x) * lerpSpeed;
}

// -------------------------------------------------------------
// GSAP TIMELINE ORCHESTRATOR
// -------------------------------------------------------------
function startMainIntroTimeline() {
    isIntroPlaying = true;
    const tl = gsap.timeline({
        onComplete: () => {
            isIntroComplete = true;
            isIntroPlaying = false;
            controls.enabled = true;
            
            // Re-enable and reset controls camera limits and targets
            controls.target.set(-1.0, 1.2, 0); 
            controls.update();

            // Fade in LHS Hint
            gsap.to('.inspection-hint', { opacity: 0.8, y: 0, duration: 0.8 });
        }
    });

    // Reset initial states
    isIntroComplete = false;
    controls.enabled = false;
    robotGroup.position.set(0, 0, -15);
    somersaultProgress.value = 0;
    camera.position.set(0, 2.5, 8);
    controls.target.set(0, 1.2, 0);
    controls.update();

    // PHASE 1: Running Entrance (Robot runs from z = -15 to z = 0)
    tl.to(robotGroup.position, {
        z: 0,
        duration: 2.8,
        ease: 'power1.out',
        onStart: () => {
            activeState = 'run';
            if (isGLTFLoaded) playGLTFAnimation('Run');
        }
    });

    // PHASE 2: Somersault Climax (Center Screen jump & flip)
    tl.to(somersaultProgress, {
        value: 1.0,
        duration: 1.6,
        ease: 'power2.inOut',
        onStart: () => {
            activeState = 'somersault';
            if (isGLTFLoaded) playGLTFAnimation('Somersault');
        },
        onComplete: () => {
            // Screen shake effect on landing
            gsap.to(camera.position, { y: 2.3, duration: 0.08, yoyo: true, repeat: 3 });
        }
    }, "+=0.15");

    // PHASE 3: Shift to LHS & Pan Camera
    tl.to(robotGroup.position, {
        x: -2.3,
        duration: 2.0,
        ease: 'power3.inOut',
        onStart: () => {
            // Blend into Idle/Pose pose
            activeState = 'pose';
            if (isGLTFLoaded) playGLTFAnimation('Pose');
        }
    }, "+=0.25");

    // Smoothly pan camera targets to frame split-screen LHS
    tl.to(controls.target, {
        x: -1.0,
        duration: 2.0,
        ease: 'power3.inOut',
        onUpdate: () => {
            controls.update();
        }
    }, "<"); // Run concurrently

    tl.to(camera.position, {
        x: 0,
        y: 2.2,
        z: 5.2,
        duration: 2.0,
        ease: 'power3.inOut',
        onUpdate: () => {
            controls.update();
        }
    }, "<");

    // PHASE 4: Specs Card Slide-in (RHS)
    tl.to('#specs-card', {
        x: '0%',
        opacity: 1,
        duration: 1.2,
        ease: 'power4.out',
        onStart: () => {
            triggerTerminalLogs();
        }
    }, "-=0.9");
}

// -------------------------------------------------------------
// TECHNICAL SPECIFICATIONS CARD TERMINAL LOG TYPING EFFECT
// -------------------------------------------------------------
function triggerTerminalLogs() {
    const lines = [
        "> Link established on SECURE_NET_80",
        "> Synaptic link calibration: NOMINAL",
        "> Loading Orbit-05 core specs...",
        "> Unit Status: READY FOR DIAGNOSTIC HOVER"
    ];
    
    diagnosticConsole.innerHTML = '';
    
    lines.forEach((line, index) => {
        setTimeout(() => {
            const p = document.createElement('p');
            p.className = 'console-line';
            if (line.includes('NOMINAL')) p.classList.add('text-green');
            if (line.includes('HOVER')) p.classList.add('text-magenta');
            p.textContent = line;
            diagnosticConsole.appendChild(p);
            
            // Auto scroll console
            diagnosticConsole.scrollTop = diagnosticConsole.scrollHeight;
        }, index * 400);
    });
}

// -------------------------------------------------------------
// INTERACTIVE RAYCASTING (Hovering Body Parts)
// -------------------------------------------------------------
function onMouseMove(event) {
    // Convert mouse coordinates to standardized WebGL coordinates (-1 to +1)
    mouse.x = (event.clientX / window.innerWidth) * 2 - 1;
    mouse.y = -(event.clientY / window.innerHeight) * 2 + 1;

    // Track mouse coordinates for tooltip positioning
    if (isIntroComplete) {
        tooltip.style.left = `${event.clientX}px`;
        tooltip.style.top = `${event.clientY}px`;
    }
}

function handleRaycasting() {
    if (!isIntroComplete) return;

    // Cast rays from camera through mouse coordinates
    raycaster.setFromCamera(mouse, camera);
    
    // Check intersections on robotGroup meshes
    const intersects = raycaster.intersectObjects(robotGroup.children, true);

    if (intersects.length > 0) {
        // Find nearest mesh object with userData part definition
        let intersectedMesh = null;
        for (let i = 0; i < intersects.length; i++) {
            if (intersects[i].object.isMesh && intersects[i].object.userData.part) {
                intersectedMesh = intersects[i].object;
                break;
            }
        }

        if (intersectedMesh) {
            const partName = intersectedMesh.userData.part;
            const fullName = intersectedMesh.userData.fullName;
            const specs = intersectedMesh.userData.specs;

            // Trigger hover glow highlight
            highlightPart(partName);

            // Display Tooltip
            tooltipTitle.textContent = fullName.toUpperCase();
            tooltipBody.textContent = specs;
            tooltip.classList.add('active');

            // Update Specs Card diagnostic panel
            activePartId.textContent = partName.toUpperCase();
            activePartId.style.color = 'var(--neon-cyan)';
            
            // Throttle diagnostic prints to prevent constant text resets
            if (hoveredPartName !== partName) {
                diagnosticConsole.innerHTML = `
                    <p class="console-line text-green">> INSPECTING NODE: ${partName.toUpperCase()}</p>
                    <p class="console-line">> ${specs}</p>
                    <p class="console-line">> Core frequency: 4.8 GHz | Integrity: STABLE</p>
                `;
            }
            
            hoveredPartName = partName;
            document.body.style.cursor = 'pointer';
            return;
        }
    }

    // No valid target intersected
    resetHighlight();
    tooltip.classList.remove('active');
    activePartId.textContent = 'INTEGRATED';
    activePartId.style.color = '';
    
    if (hoveredPartName !== null) {
        diagnosticConsole.innerHTML = `
            <p class="console-line text-green">> System fully operational.</p>
            <p class="console-line">> Ready for physical inspection...</p>
        `;
    }
    
    hoveredPartName = null;
    document.body.style.cursor = 'default';
}

function highlightPart(partName) {
    if (hoveredPartName === partName) return;

    // Reset previous glowing parts
    resetHighlight();

    // Traverse robot nodes and light up matches
    robotGroup.traverse((node) => {
        if (node.isMesh && node.userData.part === partName) {
            // Skip highlighting the face screen so the eyes and smile stay perfectly visible!
            if (node.material.name === 'faceMaterial') return;

            // Store original emissive parameters
            if (!originalEmissiveMap.has(node.uuid)) {
                originalEmissiveMap.set(node.uuid, {
                    color: node.material.emissive.getHex(),
                    intensity: node.material.emissiveIntensity
                });
            }

            // Apply glowing cyan highlight
            node.material.emissive.setHex(0x00f0ff);
            node.material.emissiveIntensity = 1.6;
        }
    });
}

function resetHighlight() {
    if (!hoveredPartName) return;

    robotGroup.traverse((node) => {
        if (node.isMesh && node.userData.part === hoveredPartName) {
            const orig = originalEmissiveMap.get(node.uuid);
            if (orig) {
                node.material.emissive.setHex(orig.color);
                node.material.emissiveIntensity = orig.intensity;
            }
        }
    });
}

// -------------------------------------------------------------
// BOOT LOADING SCREEN FADE-OUT
// -------------------------------------------------------------
function simulateLoader() {
    const progressFill = document.querySelector('.progress-fill');
    const statusText = document.querySelector('.status-text');
    const loaderTerminal = document.getElementById('loader-terminal');
    
    let progress = 0;
    
    const logs = [
        "> Resolving WebGL pipelines...",
        "> Compiling PBR Shader maps...",
        "> Link calibration completed.",
        "> Loading sensory arrays...",
        "> Injecting animation matrices...",
        "> Core boot sequence: SUCCESS"
    ];

    const interval = setInterval(() => {
        progress += Math.floor(Math.random() * 8) + 3;
        if (progress >= 100) {
            progress = 100;
            clearInterval(interval);
            
            // Finish terminal loading logs
            const p = document.createElement('p');
            p.textContent = logs[logs.length - 1];
            p.style.color = 'var(--neon-emerald)';
            loaderTerminal.appendChild(p);

            statusText.textContent = "COGNITIVE ARCHITECTURE COMMITTED";

            // Fade out loader page overlay
            setTimeout(() => {
                gsap.to('#loader', {
                    opacity: 0,
                    pointerEvents: 'none',
                    duration: 0.8,
                    ease: 'power2.out',
                    onComplete: () => {
                        // Set up Phase 1 initial states
                        setActivePhase(1);
                    }
                });
            }, 500);
        }

        progressFill.style.width = `${progress}%`;
        
        // Print random boot logs during percentage increases
        if (progress % 12 === 0 && logs.length > 0) {
            const printLog = logs.shift();
            const p = document.createElement('p');
            p.textContent = printLog;
            loaderTerminal.appendChild(p);
            loaderTerminal.scrollTop = loaderTerminal.scrollHeight;
        }
    }, 80);
}

// -------------------------------------------------------------
// RESPONSIVE RESIZING
// -------------------------------------------------------------
function onWindowResize() {
    camera.aspect = window.innerWidth / window.innerHeight;
    camera.updateProjectionMatrix();
    
    renderer.setSize(window.innerWidth, window.innerHeight);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
}

// -------------------------------------------------------------
// ANIMATION FRAME RENDER LOOP
// -------------------------------------------------------------
function animate() {
    requestAnimationFrame(animate);

    const time = clock.getElapsedTime();
    const delta = clock.getDelta();

    // 1. Update Blinking Face Texture Expression
    updateFaceBlink(time);

    // Rotate and bob Mini Helper Bot (Phase 1)
    if (miniRobot && currentPhase === 1) {
        miniRobot.rotation.y += 0.006;
        miniRobot.position.y = 0.3 + Math.sin(time * 1.5) * 0.04;
    }

    // Rotate and bob Yellow Cat Bot (Phase 3)
    if (catRobot && currentPhase === 3) {
        catRobot.rotation.y += 0.006;
        catRobot.position.y = 0.3 + Math.sin(time * 1.5) * 0.04;
    }

    // 2. Drive procedural animations if GLTF loader isn't active
    updateProceduralAnimations(time);

    // 3. Update GLTF Animation Mixer
    if (mixer) {
        mixer.update(delta);
    }

    // 4. Update camera orbit physics controls
    if (controls.enabled) {
        controls.update();
    }

    // 5. Check cursor raycasting targets
    handleRaycasting();

    // 6. Render Frame
    renderer.render(scene, camera);
}

// Initialize Application once DOM is ready
if (document.readyState === 'complete' || document.readyState === 'interactive') {
    init();
    animate();
} else {
    window.addEventListener('DOMContentLoaded', () => {
        init();
        animate();
    });
}

// Hook Replay animation sequence button triggers
document.getElementById('btn-reanimate').addEventListener('click', () => {
    // Hide specifications card & hint overlay
    gsap.to('#specs-card', { x: '120%', opacity: 0, duration: 0.6, ease: 'power3.in' });
    gsap.to('.inspection-hint', { opacity: 0, y: 20, duration: 0.4 });
    
    // Relaunch sequence
    setTimeout(() => {
        startMainIntroTimeline();
    }, 600);
});

// -------------------------------------------------------------
// SCROLL Snap Observer & Reset Handler
// -------------------------------------------------------------
let currentPhase = 0;
let isIntroPlaying = false;

function resetIntroTimeline() {
    isIntroComplete = false;
    isIntroPlaying = false;
    controls.enabled = false;
    
    // Hide UI elements
    gsap.to('#specs-card', { x: '120%', opacity: 0, duration: 0.4 });
    gsap.to('.inspection-hint', { opacity: 0, y: 20, duration: 0.3 });
    
    // Reset robot group position & rotation (tucked back in fog)
    robotGroup.position.set(0, 0, -15);
    somersaultProgress.value = 0;
    activeState = 'idle'; // Reset state to idle
    if (isGLTFLoaded) playGLTFAnimation('Idle');
    
    // Reset camera target
    controls.target.set(0, 1.2, 0);
    camera.position.set(0, 2.5, 8);
    controls.update();
}

function setActivePhase(phaseNum) {
    if (phaseNum === currentPhase) return;
    currentPhase = phaseNum;

    // 1. Update navigation items
    const navLinks = document.querySelectorAll('.nav-link');
    navLinks.forEach((link, idx) => {
        if (idx === phaseNum - 1) {
            link.classList.add('active');
        } else {
            link.classList.remove('active');
        }
    });

    // 2. Update lateral dots
    const dots = document.querySelectorAll('.phase-dots .dot');
    dots.forEach((dot, idx) => {
        if (idx === phaseNum - 1) {
            dot.classList.add('active');
        } else {
            dot.classList.remove('active');
        }
    });

    // 3. Coordinate transitions for canvas and hologram
    const canvasContainer = document.getElementById('canvas-container');
    const bgHologram = document.querySelector('.bg-hologram');

    // Kill any active robot/camera tweens to prevent clashing
    gsap.killTweensOf(robotGroup.position);
    gsap.killTweensOf(camera.position);
    gsap.killTweensOf(controls.target);
    if (miniRobot) {
        gsap.killTweensOf(miniRobot.position);
        gsap.killTweensOf(miniRobot.scale);
    }
    if (catRobot) {
        gsap.killTweensOf(catRobot.position);
        gsap.killTweensOf(catRobot.scale);
    }

    if (phaseNum === 1) {
        // Phase 1: Show 3D Canvas with rotating miniRobot, hide hologram
        if (bgHologram) bgHologram.classList.remove('active');
        if (canvasContainer) canvasContainer.classList.add('active');

        controls.enabled = false;

        // Transition Mini helper bot back to Phase 1 foreground layout
        if (miniRobot) {
            gsap.to(miniRobot.scale, { x: 1.7, y: 1.7, z: 1.7, duration: 1.2, ease: 'power2.out' });
            gsap.to(miniRobot.position, { x: 1.6, y: 0.3, z: 0, duration: 1.2, ease: 'power2.out' });
        }
        if (catRobot) {
            gsap.to(catRobot.scale, { x: 0, y: 0, z: 0, duration: 0.8, ease: 'power2.in' });
            gsap.to(catRobot.position, { x: -1.5, y: 1.0, z: -8, duration: 0.8, ease: 'power2.in' });
        }

        // Transition Camera to focus on Features Section
        gsap.to(camera.position, { x: 0, y: 1.8, z: 6.5, duration: 1.5, ease: 'power2.out', onUpdate: () => controls.update() });
        gsap.to(controls.target, { x: 0, y: 1.0, z: 0, duration: 1.5, ease: 'power2.out', onUpdate: () => controls.update() });

        // Hide Phase 2 Specs UI & Retreat orange robot back to deep background fog
        gsap.to('#specs-card', { x: '120%', opacity: 0, duration: 0.8, ease: 'power3.inOut' });
        gsap.to('.inspection-hint', { opacity: 0, y: 20, duration: 0.5 });
        
        gsap.to(robotGroup.position, { x: 0, y: 0, z: -15, duration: 1.2, ease: 'power2.inOut' });
        resetIntroTimeline();

    } else if (phaseNum === 2) {
        // Phase 2: Show 3D Canvas, hide hologram
        if (bgHologram) bgHologram.classList.remove('active');
        if (canvasContainer) canvasContainer.classList.add('active');

        // Shrink and retreat helper bot into the background fog
        if (miniRobot) {
            gsap.to(miniRobot.scale, { x: 0, y: 0, z: 0, duration: 0.8, ease: 'power2.in' });
            gsap.to(miniRobot.position, { x: 0, y: 1.0, z: -8, duration: 0.8, ease: 'power2.in' });
        }
        if (catRobot) {
            gsap.to(catRobot.scale, { x: 0, y: 0, z: 0, duration: 0.8, ease: 'power2.in' });
            gsap.to(catRobot.position, { x: -1.5, y: 1.0, z: -8, duration: 0.8, ease: 'power2.in' });
        }

        // If the somersault intro hasn't completed and is not currently playing, start it!
        if (!isIntroComplete && !isIntroPlaying) {
            isIntroPlaying = true;
            startMainIntroTimeline();
        } else if (isIntroComplete) {
            // If already run once, transition robot and camera back to specifications frame
            controls.enabled = true;
            gsap.to(robotGroup.position, { x: -2.3, y: 0, z: 0, duration: 1.5, ease: 'power2.out' });
            gsap.to(controls.target, { x: -1.0, y: 1.2, z: 0, duration: 1.5, ease: 'power2.out', onUpdate: () => controls.update() });
            gsap.to(camera.position, { x: 0, y: 2.2, z: 5.2, duration: 1.5, ease: 'power2.out', onUpdate: () => controls.update() });
            
            activeState = 'pose';
            if (isGLTFLoaded) playGLTFAnimation('Pose');

            gsap.to('#specs-card', { x: '0%', opacity: 1, duration: 0.8, ease: 'power2.out' });
            gsap.to('.inspection-hint', { opacity: 0.8, y: 0, duration: 0.8 });
        }

    } else if (phaseNum === 3) {
        // Phase 3: Keep 3D canvas active and fade in hologram head background behind it
        if (canvasContainer) canvasContainer.classList.add('active');
        if (bgHologram) bgHologram.classList.add('active');

        controls.enabled = false;

        // Make helper bot hidden
        if (miniRobot) {
            miniRobot.scale.set(0, 0, 0);
        }

        // Transition Yellow Cat Bot into Phase 3 layout
        if (catRobot) {
            gsap.to(catRobot.scale, { x: 1.7, y: 1.7, z: 1.7, duration: 1.2, ease: 'power2.out' });
            gsap.to(catRobot.position, { x: -1.5, y: 0.3, z: 0, duration: 1.2, ease: 'power2.out' });
        }

        // Smoothly retreat main orange robot back into deep background fog (return to dock)
        gsap.to(robotGroup.position, { x: 0, y: 0, z: -15, duration: 1.5, ease: 'power2.inOut' });
        
        // Sweep/pan camera to frame Contact Form on RHS/center (Heroic perspective, framed lower to prevent header navigation clipping)
        gsap.to(camera.position, { x: -2.7, y: 0.8, z: 3.1, duration: 1.5, ease: 'power2.inOut', onUpdate: () => controls.update() });
        gsap.to(controls.target, { x: -1.5, y: 0.75, z: 0, duration: 1.5, ease: 'power2.inOut', onUpdate: () => controls.update() });

        // Hide specifications UI overlays
        gsap.to('#specs-card', { x: '120%', opacity: 0, duration: 0.8, ease: 'power3.inOut' });
        gsap.to('.inspection-hint', { opacity: 0, y: 20, duration: 0.5 });
    }
}

window.switchPhase = function(phaseNum) {
    let targetId = '';
    if (phaseNum === 1) targetId = 'panel-features';
    else if (phaseNum === 2) targetId = 'panel-overview';
    else if (phaseNum === 3) targetId = 'panel-contact';
    
    const targetElement = document.getElementById(targetId);
    if (targetElement) {
        targetElement.scrollIntoView({ behavior: 'smooth' });
    }
};

function setupScrollObserver() {
    const panels = document.querySelectorAll('.panel-container');
    
    const observer = new IntersectionObserver((entries) => {
        entries.forEach(entry => {
            if (entry.isIntersecting) {
                const phase = parseInt(entry.target.getAttribute('data-phase'));
                if (phase) {
                    setActivePhase(phase);
                }
            }
        });
    }, {
        threshold: 0.45 // Trigger when 45% of the panel is visible on screen
    });
    
    panels.forEach(panel => {
        observer.observe(panel);
    });
}

// -------------------------------------------------------------
// SEARCH ENGINE & CONTACT FORM FEATURES (Phase 1 & Phase 3)
// -------------------------------------------------------------
function setupInteractiveFeatures() {
    // Section 1: Search Database
    const searchInput = document.getElementById('search-db');
    const searchBtn = document.getElementById('btn-search');
    const searchResults = document.getElementById('search-results');
    
    function runSearch() {
        const query = searchInput.value.toLowerCase().trim();
        if (!query) return;
        
        searchResults.innerHTML = `<p class="console-line">> Searching for "${query.toUpperCase()}"...</p>`;
        
        setTimeout(() => {
            let reply = '';
            if (query.includes('orbit') || query.includes('robot') || query.includes('05')) {
                reply = `> MATCH FOUND: ORBIT-05 COGNITIVE UNIT.<br>> Type: Tactical Reconnaissance<br>> Status: ONLINE / LHS STANDBY.`;
            } else if (query.includes('core') || query.includes('fusion') || query.includes('battery') || query.includes('power')) {
                reply = `> MATCH FOUND: QUANTUM CORE DRIVE.<br>> Charge: 87.2%<br>> Stability: 100% (NOMINAL).`;
            } else if (query.includes('synapse') || query.includes('cognition') || query.includes('brain') || query.includes('mind')) {
                reply = `> MATCH FOUND: SYNAPSE COGNITIVE LINK.<br>> Version: v4.2 quantum logic<br>> Integrity Sync: 98.4%.`;
            } else if (query.includes('elamanitech')) {
                reply = `> DATABASE ACCESS GRANTED.<br>> Elamanitech Core Sector Grid.<br>> Office hubs: Tokyo, Berlin, Neo-SF.`;
            } else {
                reply = `> SEARCH COMPLETED: 0 RESULTS FOUND.<br>> ERROR: Query encrypted or restricted.`;
            }
            searchResults.innerHTML = `<p class="console-line text-green">${reply}</p>`;
        }, 500);
    }
    
    searchBtn.addEventListener('click', runSearch);
    searchInput.addEventListener('keydown', (e) => {
        if (e.key === 'Enter') runSearch();
    });
    
    // Section 3: Comms Form Transmission
    const form = document.getElementById('cyber-form');
    const feedback = document.getElementById('form-feedback');
    
    form.addEventListener('submit', () => {
        feedback.style.display = 'block';
        feedback.innerHTML = `<p class="console-line">> Transmitting packet...</p>`;
        
        setTimeout(() => {
            feedback.innerHTML = `<p class="console-line text-green">> Packets encrypted successfully.<br>> Transmission completed. Comms link ESTABLISHED.</p>`;
            form.reset();
        }, 1200);
    });
}

